    private void ManageEpisode()
    {
        SharedAcademy.EpisodeTimeout -= Time.deltaTime;

        int remainingFoodCount = foodSpawner.GetComponentsInChildren<Food>().Length;

        if (SharedAcademy.EpisodeTimeout <= 0 || remainingFoodCount == 0)
        {
