        float moveVertical = actions.ContinuousActions[1];

        Vector2 movement = new Vector2(moveHorizontal, moveVertical);
        rb.AddForce(movement * speed);

        float minDistance = float.MaxValue;
        foreach (var food in foodSpawner.GetComponentsInChildren<Food>())
        {
            float distance = Vector2.Distance(transform.position, food.transform.position);
            if (distance < minDistance)
            {
                minDistance = distance;
            }
        }

        // Add a penalty proportional to the distance to the nearest food.
        SetReward(-minDistance * Time.fixedDeltaTime);
    }

    public void AddRewardOnEatingFood()
    {
        AddReward(1f);
    }

    public override void Heuristic(in ActionBuffers actionsOut)
    {
        var continuousActionsOut = actionsOut.ContinuousActions;
        continuousActionsOut[0] = Input.GetAxis("Horizontal");
        continuousActionsOut[1] = Input.GetAxis("Vertical");
    }

    public void ResetPlayerEpisode()
    {
        EndEpisode();
        transform.position = initialPosition; // Reset player position to the initial position
