public override void CollectObservations(VectorSensor sensor)
{
    int initialObservationCount = sensor.observationBuffer.Length;

    // The observations from the ray-based sensor will be automatically collected

    int finalObservationCount = sensor.observationBuffer.Length;
    int numberOfObservations = finalObservationCount - initialObservationCount;
    Debug.Log("Number of Observations: " + numberOfObservations);
